namespace sv_2b3253df78dd41b0bd1dfd19dd005541.Models;

// Domain records (immutable contracts)
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models used during editing
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate ?? DateTime.Today, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@* Horizontal step progress bar *@

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var state = GetStepState(step);
            <li class="step-item @state" @onclick="() => OnStepClick(step)" role="button"
                aria-current="@(step == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (CompletedSteps.Contains(step))
                    {
                        <span aria-hidden="true">✓</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
                <span class="step-label">@StepNames[step]</span>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private string GetStepState(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "dimmed";
    }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-list::before {
    content: '';
    position: absolute;
    top: 18px;
    left: 5%;
    right: 5%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    z-index: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    margin-bottom: 0.5rem;
    transition: all 0.2s;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    max-width: 100px;
}

/* States */
.step-item.active .step-circle {
    background: #0d6efd;
    color: #fff;
    box-shadow: 0 0 0 4px rgba(13, 110, 253, 0.25);
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-circle {
    background: #198754;
    color: #fff;
    cursor: pointer;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

.step-item.dimmed .step-circle {
    background: #e9ecef;
    color: #6c757d;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

