@* Horizontal step progress bar *@

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var state = GetStepState(step);
            <li class="step-item @state" @onclick="() => OnStepClick(step)" role="button"
                aria-current="@(step == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (CompletedSteps.Contains(step))
                    {
                        <span aria-hidden="true">✓</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
                <span class="step-label">@StepNames[step]</span>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private string GetStepState(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "dimmed";
    }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

