toolArgs.file_text:
.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-list::before {
    content: '';
    position: absolute;
    top: 18px;
    left: 5%;
    right: 5%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    z-index: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    margin-bottom: 0.5rem;
    transition: all 0.2s;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    max-width: 100px;
}

/* States */
.step-item.active .step-circle {
    background: #0d6efd;
    color: #fff;
    box-shadow: 0 0 0 4px rgba(13, 110, 253, 0.25);
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-circle {
    background: #198754;
    color: #fff;
    cursor: pointer;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

.step-item.dimmed .step-circle {
    background: #e9ecef;
    color: #6c757d;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

