toolArgs.file_text:
@using sv_2b3253df78dd41b0bd1dfd19dd005541.Models

<div>
    <h4 class="mb-3">Review &amp; Submit</h4>

    @if (Submitted)
    {
        <div class="alert alert-success">
            <h5 class="alert-heading">Application Submitted!</h5>
            <p>Your application has been received. Your application ID is <strong>#@ApplicationId</strong>.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        @* Personal Info *@
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <div class="card-body">
                <dl class="row mb-0">
                    <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
                </dl>
            </div>
        </div>

        @* Work History *@
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-3">
                        <h6>@entry.Title at @entry.Company</h6>
                        <p class="text-muted small mb-1">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </p>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0">@entry.Description</p>
                        }
                    </div>
                }
            </div>
        </div>

        @* References *@
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var r in References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <small class="text-muted">@r.Email · @r.Phone</small>
                    </div>
                }
            </div>
        </div>

        @* Cover Letter *@
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@CoverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Submit Application
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public IApplicationService AppService { get; set; } = default!;
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public bool Submitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }

    private bool isSubmitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            var id = await AppService.SubmitApplicationAsync(application);
            await OnSubmitted.InvokeAsync(id);
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

