@page "/apply"
@rendermode InteractiveServer
@using sv_2b3253df78dd41b0bd1dfd19dd005541.Models
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   StepNames="stepNames"
                   OnStepSelected="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              AppService="AppService"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        AppService="AppService"
                        Submitted="submitted"
                        ApplicationId="applicationId"
                        OnEditStep="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmitted="HandleSubmitted" />
            break;
    }
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = new();

    private readonly List<string> stepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    // Form state owned by the page
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private bool submitted;
    private int applicationId;

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void HandleSubmitted(int id)
    {
        applicationId = id;
        submitted = true;
        completedSteps.Add(currentStep);
    }
}

